    private void btnSavePersonActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnSavePersonActionPerformed
try {
            
            ec.edu.espe.Billing.model.Person person = new ec.edu.espe.Billing.model.Person(
                txtPersonId.getText(), 
                txtPersonName.getText(), 
                txtPersonEmail.getText()
            );
            
           
            controller.saveOrUpdatePerson(person);
            
            
            javax.swing.JOptionPane.showMessageDialog(this, "Person saved successfully!");
        } catch (Exception ex) {
            javax.swing.JOptionPane.showMessageDialog(this, "Error saving person: " + ex.getMessage());
        }

    }//GEN-LAST:event_btnSavePersonActionPerformed

    private void btnLoadPersonActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnLoadPersonActionPerformed
ec.edu.espe.Billing.model.Person person = controller.findPerson(txtPersonId.getText());
    if (person != null) {
        txtPersonName.setText(person.getName());
        txtPersonEmail.setText(person.getEmail());
    } else {
        javax.swing.JOptionPane.showMessageDialog(this, "Person not found!");
    }
    }//GEN-LAST:event_btnLoadPersonActionPerformed

    private void btnSaveProductActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnSaveProductActionPerformed
   try {
        double price = (Double) spnProductPrice.getValue();
        ec.edu.espe.Billing.model.Product product = new ec.edu.espe.Billing.model.Product(txtProductId.getText(), txtProductName.getText(), price);
        controller.saveOrUpdateProduct(product);
        javax.swing.JOptionPane.showMessageDialog(this, "Product saved successfully!");
    } catch (Exception ex) {
        javax.swing.JOptionPane.showMessageDialog(this, "Error saving product: " + ex.getMessage());
    }
    }//GEN-LAST:event_btnSaveProductActionPerformed

    private void btnLoadProductActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnLoadProductActionPerformed
 ec.edu.espe.Billing.model.Product product = controller.findProduct(txtProductId.getText());
    if (product != null) {
        txtProductName.setText(product.getName());
        spnProductPrice.setValue(product.getPrice());
    } else {
        javax.swing.JOptionPane.showMessageDialog(this, "Product not found!");
    }
    }//GEN-LAST:event_btnLoadProductActionPerformed

    private void btnSavePaymentActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnSavePaymentActionPerformed
try {
        double amount = (Double) spnPaymentAmount.getValue();
        String method = cmbPaymentMethod.getSelectedItem().toString();
        ec.edu.espe.Billing.model.Payment payment = new ec.edu.espe.Billing.model.Payment(txtPaymentId.getText(), method, amount);
        controller.saveOrUpdatePayment(payment);
        javax.swing.JOptionPane.showMessageDialog(this, "Payment saved successfully!");
    } catch (Exception ex) {
        javax.swing.JOptionPane.showMessageDialog(this, "Error saving payment: " + ex.getMessage());
    }
    }//GEN-LAST:event_btnSavePaymentActionPerformed

    private void btnLoadPaymentActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnLoadPaymentActionPerformed
 ec.edu.espe.Billing.model.Payment payment = controller.findPayment(txtPaymentId.getText());
    if (payment != null) {
        cmbPaymentMethod.setSelectedItem(payment.getPaymentMethod());
        spnPaymentAmount.setValue(payment.getAmount());
    } else {
        javax.swing.JOptionPane.showMessageDialog(this, "Payment not found!");
    }
    }//GEN-LAST:event_btnLoadPaymentActionPerformed

